public class LineExample : MonoBehaviour
{
    private LineRenderer lineRenderer;

    void Start()
    {
        lineRenderer = gameObject.AddComponent<LineRenderer>();
        lineRenderer.positionCount = 2;
        lineRenderer.SetPosition(0, new Vector3(0, 0, 0));
        lineRenderer.SetPosition(1, new Vector3(1, 1, 0));
    }
}
```

For polylines, you can increase the `positionCount` and call `SetPositions` with an array of `Vector3` points.

### MonoGame/XNA
In MonoGame (formerly XNA), you don't have a built-in `Line` class. Instead, you would create your own abstractions or directly use the `SpriteBatch` to draw lines using 1-pixel wide textures stretched between two points.

```csharp
public void DrawLine(SpriteBatch spriteBatch, Texture2D pixel, Vector2 point1, Vector2 point2, Color color)
{
    Vector2 edge = point2 - point1;
    float angle = (float)Math.Atan2(edge.Y, edge.X);

    spriteBatch.Draw(pixel, new Rectangle((int)point1.X, (int)point1.Y, (int)edge.Length(), 1), 
        null, color, angle, new Vector2(0, 0), SpriteEffects.None, 0);
}
```

For polylines, you would call this method in a loop for every segment of the polyline.

